package service

import (
	"encoding/json"
	"fmt"
	"strings"

	"xingyunpan-v2/internal/model"
	"xingyunpan-v2/internal/repository"
)

type EmailTemplateLanguagePayload struct {
	Code    string `json:"code"`
	Label   string `json:"label"`
	Subject string `json:"subject"`
	Content string `json:"content"`
}

type EmailTemplatePayload struct {
	TemplateKey string                         `json:"template_key"`
	Name        string                         `json:"name"`
	Description string                         `json:"description"`
	Status      string                         `json:"status"`
	StatusTone  string                         `json:"status_tone"`
	Pro         bool                           `json:"pro"`
	Languages   []EmailTemplateLanguagePayload `json:"languages"`
}

type ResolvedEmailTemplate struct {
	TemplateKey string
	Name        string
	Language    string
	Subject     string
	Content     string
}

type EmailTemplateService interface {
	List() ([]EmailTemplatePayload, error)
	GetByKey(templateKey string) (*EmailTemplatePayload, error)
	Update(templateKey string, payload *EmailTemplatePayload) (*EmailTemplatePayload, error)
}

type emailTemplateService struct {
	repo repository.EmailTemplateRepository
}

func NewEmailTemplateService(repo repository.EmailTemplateRepository) EmailTemplateService {
	return &emailTemplateService{repo: repo}
}

func (s *emailTemplateService) List() ([]EmailTemplatePayload, error) {
	templates, err := s.repo.List()
	if err != nil {
		return nil, err
	}
	if len(templates) == 0 {
		return defaultEmailTemplates(), nil
	}
	result := make([]EmailTemplatePayload, 0, len(templates))
	for _, item := range templates {
		payload, err := toEmailTemplatePayload(&item)
		if err != nil {
			return nil, err
		}
		result = append(result, *payload)
	}
	return result, nil
}

func (s *emailTemplateService) GetByKey(templateKey string) (*EmailTemplatePayload, error) {
	return ResolveEmailTemplatePayload(s.repo, templateKey)
}

func (s *emailTemplateService) Update(templateKey string, payload *EmailTemplatePayload) (*EmailTemplatePayload, error) {
	if payload == nil {
		return nil, fmt.Errorf("email template payload is required")
	}
	templateKey = strings.TrimSpace(templateKey)
	if templateKey == "" {
		templateKey = strings.TrimSpace(payload.TemplateKey)
	}
	if templateKey == "" {
		return nil, fmt.Errorf("template key is required")
	}

	normalized := normalizeEmailTemplatePayload(payload)
	if normalized.Name == "" {
		return nil, fmt.Errorf("template name is required")
	}
	if len(normalized.Languages) == 0 {
		return nil, fmt.Errorf("at least one language variant is required")
	}

	entity, err := s.repo.GetByKey(templateKey)
	if err != nil {
		return nil, err
	}
	if entity == nil {
		entity = &model.EmailTemplate{TemplateKey: templateKey}
	}

	languagesJSON, err := json.Marshal(normalized.Languages)
	if err != nil {
		return nil, fmt.Errorf("marshal template languages failed: %w", err)
	}

	entity.TemplateKey = templateKey
	entity.Name = normalized.Name
	entity.Description = normalized.Description
	entity.Status = normalized.Status
	entity.StatusTone = normalized.StatusTone
	entity.Pro = normalized.Pro
	entity.LanguagesJSON = string(languagesJSON)
	if err := s.repo.Save(entity); err != nil {
		return nil, err
	}
	return toEmailTemplatePayload(entity)
}

func ResolveEmailTemplatePayload(repo repository.EmailTemplateRepository, templateKey string) (*EmailTemplatePayload, error) {
	templateKey = strings.TrimSpace(templateKey)
	if templateKey == "" {
		return nil, fmt.Errorf("template key is required")
	}
	entity, err := repo.GetByKey(templateKey)
	if err != nil {
		return nil, err
	}
	if entity == nil {
		for _, item := range defaultEmailTemplates() {
			if item.TemplateKey == templateKey {
				copyItem := item
				return &copyItem, nil
			}
		}
		return nil, nil
	}
	return toEmailTemplatePayload(entity)
}

func ResolveEmailTemplate(repo repository.EmailTemplateRepository, templateKey string) (*ResolvedEmailTemplate, error) {
	payload, err := ResolveEmailTemplatePayload(repo, templateKey)
	if err != nil {
		return nil, err
	}
	if payload == nil {
		return nil, nil
	}
	language := chooseDefaultTemplateLanguage(payload.Languages)
	if language == nil {
		return nil, fmt.Errorf("template %q has no usable language variant", templateKey)
	}
	return &ResolvedEmailTemplate{TemplateKey: payload.TemplateKey, Name: payload.Name, Language: language.Code, Subject: language.Subject, Content: language.Content}, nil
}

func chooseDefaultTemplateLanguage(languages []EmailTemplateLanguagePayload) *EmailTemplateLanguagePayload {
	preferredCodes := []string{"zh-CN", "zh-Hans", "zh", "en-US", "en", "English", "de-DE", "de", "Deutsch"}
	for _, preferred := range preferredCodes {
		for i := range languages {
			code := strings.TrimSpace(languages[i].Code)
			if strings.EqualFold(code, preferred) && hasRenderableTemplateContent(languages[i]) {
				return &languages[i]
			}
		}
	}
	for i := range languages {
		if hasRenderableTemplateContent(languages[i]) {
			return &languages[i]
		}
	}
	return nil
}

func hasRenderableTemplateContent(language EmailTemplateLanguagePayload) bool {
	return strings.TrimSpace(language.Subject) != "" || strings.TrimSpace(language.Content) != ""
}

func toEmailTemplatePayload(template *model.EmailTemplate) (*EmailTemplatePayload, error) {
	var languages []EmailTemplateLanguagePayload
	if strings.TrimSpace(template.LanguagesJSON) != "" {
		if err := json.Unmarshal([]byte(template.LanguagesJSON), &languages); err != nil {
			return nil, fmt.Errorf("unmarshal template languages failed: %w", err)
		}
	}
	return &EmailTemplatePayload{TemplateKey: template.TemplateKey, Name: template.Name, Description: template.Description, Status: template.Status, StatusTone: template.StatusTone, Pro: template.Pro, Languages: languages}, nil
}

func normalizeEmailTemplatePayload(payload *EmailTemplatePayload) *EmailTemplatePayload {
	normalized := *payload
	normalized.TemplateKey = strings.TrimSpace(normalized.TemplateKey)
	normalized.Name = strings.TrimSpace(normalized.Name)
	normalized.Description = strings.TrimSpace(normalized.Description)
	normalized.Status = strings.TrimSpace(normalized.Status)
	normalized.StatusTone = strings.TrimSpace(normalized.StatusTone)
	cleanLanguages := make([]EmailTemplateLanguagePayload, 0, len(normalized.Languages))
	for _, item := range normalized.Languages {
		item.Code = normalizeTemplateLanguageCode(item.Code)
		item.Label = strings.TrimSpace(item.Label)
		item.Subject = strings.TrimSpace(item.Subject)
		item.Content = strings.TrimSpace(item.Content)
		if item.Code == "" || item.Label == "" {
			continue
		}
		cleanLanguages = append(cleanLanguages, item)
	}
	normalized.Languages = cleanLanguages
	return &normalized
}

func normalizeTemplateLanguageCode(code string) string {
	code = strings.TrimSpace(code)
	switch strings.ToLower(code) {
	case "english", "en":
		return "en-US"
	case "deutsch", "de":
		return "de-DE"
	case "espa帽ol", "español", "es":
		return "es-ES"
	case "fran莽ais", "français", "fr":
		return "fr-FR"
	case "italiano", "it":
		return "it-IT"
	case "日本語", "ja":
		return "ja-JP"
	case "zh-hans", "zh":
		return "zh-CN"
	default:
		return code
	}
}
