func buildSimpleTemplateHTML(lang string, title string, body string, ttlText string, buttonLabel string, footerText string) string {
	return fmt.Sprintf(`<!doctype html>
<html lang="%s">
  <head><meta charset="UTF-8" /><meta name="viewport" content="width=device-width, initial-scale=1.0" /><title>%s</title></head>
  <body style="margin:0;padding:0;background:#f5f9ff;font-family:'Segoe UI',Arial,sans-serif;">
    <table role="presentation" cellpadding="0" cellspacing="0" border="0" width="100%%" style="padding:32px 16px;background:#f5f9ff;">
      <tr><td align="center">
        <table role="presentation" cellpadding="0" cellspacing="0" border="0" width="100%%" style="max-width:600px;background:#fff;border:1px solid #e7edf8;border-radius:18px;">
          <tr><td style="padding:44px 42px 32px;">
            <a href="{{ .CommonContext.SiteUrl }}"><img src="{{ .CommonContext.Logo.Normal }}" alt="{{ .CommonContext.SiteBasic.Name }}" style="display:block;width:100px;height:auto;border:0;" /></a>
            <div style="height:22px"></div><h1 style="margin:0 0 18px;font-size:24px;line-height:28px;color:#141414;">%s</h1>
            <p style="margin:0 0 10px;font-size:15px;line-height:25px;color:#141414;">%s</p>
            <p style="margin:0 0 24px;font-size:14px;line-height:22px;color:#64748b;">%s</p>
            <a href="{{ .Url }}" style="display:inline-block;padding:0 23px;line-height:44px;border-radius:999px;background:#0666eb;color:#fff;text-decoration:none;font-weight:700;">%s</a>
            <div style="height:24px"></div><p style="margin:0;font-size:13px;line-height:22px;color:#64748b;">{{ .Url }}</p>
            <p style="margin:8px 0 0;font-size:14px;line-height:22px;color:#0666eb;">{{ .Code }}</p>
            <div style="height:24px"></div><div style="border-top:1px solid #dfe4ec;padding-top:18px;font-size:13px;line-height:20px;color:#94a3b8;">%s</div>
          </td></tr>
        </table>
      </td></tr>
    </table>
  </body>
</html>`, lang, title, title, body, ttlText, buttonLabel, footerText)
}

